class Solution {
    public int minChanges(int n, int k) {
        int count = 0;
        while (n != k) {
            if (n < k) return -1;
            int diff = n ^ k;
            if ((diff & (diff - 1)) == 0) count++;
            else {
                int rightmostSetBit = diff & -diff;
                n ^= rightmostSetBit;
                count++;
            }
        }
        return count;
    }
}
```
efficiency: HIGH
time complexity: O(log(n))
space complexity: O(1)
